package ccxt

type Extended struct {
   *ExtendedCore
   Core *ExtendedCore
   exchangeTyped *ExchangeTyped
}

func NewExtended(userConfig map[string]any) *Extended {
   p := NewExtendedCore()
   p.Init(userConfig)
   return &Extended{
       ExtendedCore: p,
       Core:  p,
       exchangeTyped: NewExchangeTyped(&p.Exchange),
   }
}
func NewExtendedFromCore(core *ExtendedCore) *Extended {
   return &Extended{
       ExtendedCore: core,
       Core:  core,
       exchangeTyped: NewExchangeTyped(&core.Exchange),
   }
}

